import asyncio
import json
from dataclasses import dataclass, field
from typing import Any, Callable, Awaitable


@dataclass
class StepResult:
    step_id: str
    success: bool
    output: Any
    error: str | None = None


@dataclass
class Checkpoint:
    step_id: str
    validate: Callable[[Any], tuple[bool, str]]


class SequentialOrchestrator:
    # Executes a pipeline of agents in order, with optional checkpoint validation.
    # If a checkpoint fails, execution halts and the step is retried up to max_retries.

    def __init__(
        self,
        steps: list[tuple[str, Callable[[Any], Awaitable[Any]]]],
        checkpoints: dict[str, Checkpoint] | None = None,
        max_retries: int = 2,
    ):
        self.steps = steps
        self.checkpoints = checkpoints or {}
        self.max_retries = max_retries

    async def run(self, initial_input: Any) -> list[StepResult]:
        results: list[StepResult] = []
        current_input = initial_input

        for step_id, agent_fn in self.steps:
            attempt = 0
            while attempt <= self.max_retries:
                try:
                    output = await agent_fn(current_input)
                    # Run checkpoint if defined for this step
                    if step_id in self.checkpoints:
                        checkpoint = self.checkpoints[step_id]
                        valid, reason = checkpoint.validate(output)
                        if not valid:
                            attempt += 1
                            if attempt > self.max_retries:
                                results.append(StepResult(
                                    step_id=step_id, success=False,
                                    output=None,
                                    error=f"Checkpoint failed after {self.max_retries} retries: {reason}"
                                ))
                                return results  # Halt pipeline
                            continue
                    results.append(StepResult(step_id=step_id, success=True, output=output))
                    current_input = output
                    break
                except Exception as exc:
                    attempt += 1
                    if attempt > self.max_retries:
                        results.append(StepResult(
                            step_id=step_id, success=False, output=None,
                            error=str(exc)
                        ))
                        return results
        return results


# --- Usage example ---

async def extract_agent(raw_document: str) -> dict:
    # Simulate extracting structured data from a document
    return {"entities": ["Acme Corp", "EMEA region"], "raw": raw_document}


async def classify_agent(extracted: dict) -> dict:
    # Simulate classifying extracted entities
    return {**extracted, "classification": "enterprise-contract"}


async def generate_agent(classified: dict) -> str:
    # Simulate generating a summary from classified data
    return f"Summary for {classified['classification']}: {', '.join(classified['entities'])}"


def validate_extraction(output: dict) -> tuple[bool, str]:
    if not output.get("entities"):
        return False, "No entities extracted"
    return True, ""


async def main():
    orchestrator = SequentialOrchestrator(
        steps=[
            ("extract", extract_agent),
            ("classify", classify_agent),
            ("generate", generate_agent),
        ],
        checkpoints={
            "extract": Checkpoint(step_id="extract", validate=validate_extraction),
        },
        max_retries=2,
    )
    results = await orchestrator.run("CONTRACT: Acme Corp agrees to supply widgets to EMEA region.")
    for r in results:
        status = "OK" if r.success else f"FAIL: {r.error}"
        print(f"  {r.step_id}: {status}")


if __name__ == "__main__":
    asyncio.run(main())

import asyncio
from dataclasses import dataclass
from typing import Any, Callable, Awaitable


@dataclass
class SubtaskResult:
    agent_id: str
    output: Any
    error: str | None = None


class ParallelFanOutOrchestrator:
    # Dispatches independent subtasks to multiple agents concurrently,
    # then aggregates results with a configurable strategy.

    def __init__(
        self,
        agents: dict[str, Callable[[Any], Awaitable[Any]]],
        aggregation_strategy: str = "collect",  # collect | majority_vote | first_success
        timeout_seconds: float = 30.0,
    ):
        self.agents = agents
        self.aggregation_strategy = aggregation_strategy
        self.timeout_seconds = timeout_seconds

    async def _run_with_timeout(
        self, agent_id: str, agent_fn: Callable, shared_input: Any
    ) -> SubtaskResult:
        try:
            output = await asyncio.wait_for(
                agent_fn(shared_input), timeout=self.timeout_seconds
            )
            return SubtaskResult(agent_id=agent_id, output=output)
        except asyncio.TimeoutError:
            return SubtaskResult(agent_id=agent_id, output=None, error="timeout")
        except Exception as exc:
            return SubtaskResult(agent_id=agent_id, output=None, error=str(exc))

    async def run(self, shared_input: Any) -> Any:
        tasks = [
            self._run_with_timeout(agent_id, fn, shared_input)
            for agent_id, fn in self.agents.items()
        ]
        results: list[SubtaskResult] = await asyncio.gather(*tasks)
        return self._aggregate(results)

    def _aggregate(self, results: list[SubtaskResult]) -> Any:
        successes = [r for r in results if r.error is None]
        if self.aggregation_strategy == "collect":
            return {r.agent_id: r.output for r in successes}

        if self.aggregation_strategy == "majority_vote":
            if not successes:
                return None
            # Require outputs to be hashable for simple majority vote
            from collections import Counter
            votes = Counter(str(r.output) for r in successes)
            winner, _ = votes.most_common(1)[0]
            return next(r.output for r in successes if str(r.output) == winner)

        if self.aggregation_strategy == "first_success":
            return successes[0].output if successes else None

        raise ValueError(f"Unknown aggregation strategy: {self.aggregation_strategy}")


# --- Usage example ---

async def risk_agent(contract: str) -> str:
    await asyncio.sleep(0.01)  # Simulate LLM call
    return "HIGH_RISK" if "penalty" in contract.lower() else "LOW_RISK"


async def compliance_agent(contract: str) -> list[str]:
    await asyncio.sleep(0.01)
    return ["GDPR", "SOC2"] if "data" in contract.lower() else []


async def summary_agent(contract: str) -> str:
    await asyncio.sleep(0.01)
    return f"Summary: {contract[:50]}..."


async def main():
    orchestrator = ParallelFanOutOrchestrator(
        agents={
            "risk": risk_agent,
            "compliance": compliance_agent,
            "summary": summary_agent,
        },
        aggregation_strategy="collect",
        timeout_seconds=10.0,
    )
    contract_text = "This data processing agreement includes penalty clauses for breach."
    result = await orchestrator.run(contract_text)
    for agent_id, output in result.items():
        print(f"  {agent_id}: {output}")


if __name__ == "__main__":
    asyncio.run(main())
